SELECT count(*) FROM role_type, cast_info, name, aka_name, title, char_name, kind_type, movie_companies, company_type WHERE cast_info.role_id = role_type.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND title.kind_id = kind_type.id AND movie_companies.movie_id = title.id AND movie_companies.company_type_id = company_type.id;